var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"제기랄!! 이런 망신을 당하다니!!","JPN":"くそ！！　恥かかせやがって！！","ENG":"Dammit!! That was humiliating!!","TWN":"該死！！真是丟人現眼！！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"아직 녀석들은 함선 안에 있을 거다!! 빨리 서둘러!!","JPN":"まだ奴らは艦船の中にいるはずだ！！　急げ！！","ENG":"Quick!! Those brats have to be inside that ship!!","TWN":"她們一定還在艦船裡！！動作快！！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"쥐새끼 한 마리도 빠져나가지 못하도록 철저하게 포위해!","JPN":"ネズミ一匹逃げられないように、徹底的に包囲しろ！","ENG":"Surround them and don't let a single rat get away!","TWN":"一個都不准放過，全都給我抓起來！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"대장님! 열렸습니다!","JPN":"隊長！　開きました！","ENG":"Leader! It's open!","TWN":"隊長！門開了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"좋아! 카운터의 공격을 주의하면서 단숨에 돌입한다!!","JPN":"よし！　カウンターの攻撃に注意しながら、一気に突入するぞ！！","ENG":"Okay! Watch out for the Counter and breach at once!!","TWN":"很好！衝進去！！但要注意制裁者的攻擊！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"꼼짝 마!!","JPN":"動くな！！","ENG":"Freeze!!","TWN":"全都不准動！！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"무기를 버리고 머리 위로 손 올려! 너희들은 포위……","JPN":"武器を捨てて手を頭の上に上げろ！　お前らは包囲……","ENG":"Drop your weapons and put your hands in the air! You're surr–","TWN":"放下武器，手舉起來！你們已經被包圍……"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":" 응?","JPN":" あ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하, 하하…….","JPN":"こ、ここ……","ENG":"Ha, haha...","TWN":"哈哈……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"항복이에요.","JPN":"降参です。","ENG":"I surrender.","TWN":"我投降。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"뭐, 뭐야? 왜 스태프 밖에 없어? 다른 녀석들은……?","JPN":"な、何だ？　なんでスタッフだけなんだ？　他の奴らは……？","ENG":"W-what?! Why's there only the staff member? What about the others...?","TWN":"搞什麼？怎麼只有駕駛員在？其他人呢……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MAX_CHARADE_NPC_CAP","text":{"KOREA":"설마!? 이 자식들 처음부터……!?","JPN":"まさか！？　こいつら、最初から……！？","ENG":"No way! Was their plan to...?!","TWN":"難道！？她們打從一開始就……！？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"잠깐! 이 녀석들 어디서 갑자기 튀어나온 거야!?","JPN":"おい！　お前たち、いきなりどこから現れた！？","ENG":"Wait! Where are they coming from?!","TWN":"等等！她們是從哪裡冒出來的！？"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"빨리 대장에게 연락해! 여기가 뚫리면 곧바로 거점이!","JPN":"早く隊長に連絡しろ！　ここが突破されたら、すぐ拠点が！","ENG":"Contact the leader now! If they break through here, they'll reach our base!","TWN":"快通知隊長！這裡被突破的話，再過去就是據點了！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAX_CHARADE_NPC_MOB","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAX_CHARADE_NPC_MOB","text":{"KOREA":"으악!","JPN":"うわっ！","ENG":"Agh!","TWN":"呃啊！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 말도 안 돼……. 몇 날밤을 꼬박 새서 만든 제 펜릴 코트가…….","JPN":"うう、そんなぁ……何日も夜更かしして作った私のフェンリルコートが……","ENG":"Ngh... I can't believe this... I stayed up countless nights to make this Fenrir coat...","TWN":"呃呃，怎麼這樣……人家熬夜好幾天才做好的芬里爾外套……"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"지하수도를 기어왔더니 고약한 냄새가 코트에 배어버린 것 같아요. 훌쩍.","JPN":"地下水道を這ってきたら、酷い匂いがコートに染みついちゃったみたいです。グスン。","ENG":"And the rotten stench got stuck on it while I crawled in the sewers... *Sniffle*","TWN":"沒想到竟然要爬下水道，臭水溝的味道都沾到外套上了啦，討厭。"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우갹!?","JPN":"うぎゃっ！？","ENG":"Whoa?!","TWN":"哇啊！？"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야! 얼빵이! 조심해! 하마터면 맞을 뻔 했잖아!","JPN":"おい！　間抜け！　気をつけろよ！　危うく当たるところだったじゃん！","ENG":"Hey, Goon! Watch it! You almost got hit!","TWN":"喂！小瓜呆！你小心一點！差點就被打到咧！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이길 수 있다면, 시궁창이라도 뛰어들어야지!","JPN":"勝てるなら、ドブでも何でも飛び込まないとだろ！","ENG":"We have to jump in the gutter if it'll lead to victory!","TWN":"只要能贏，就算是臭水溝也要爬！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"안 그러냐! 꼬맹이?","JPN":"そう思わないか！　おこちゃま！","ENG":"Isn't that right, kid?!","TWN":"對吧！小鬼？"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카 말이 맞아요!","JPN":"ライカの言うとおりです！","ENG":"Laika's right!","TWN":"萊卡說的沒錯！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"작전대로 밖에서 스키너가 최선을 다해 시선을 끌어주고 있어요!","JPN":"作戦どおり、外でスキナーが頑張って目を引いてくれてます！","ENG":"Skinner's doing her best to attract all of their attention out there, just like we planned!","TWN":"按照計畫，史金納現在正在外面替我們吸引敵人的注意！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 사이 우리는 최대한 빨리 거점을 제압하는 거예요!","JPN":"その間に、私たちはなるべく早く拠点を制圧するんです！","ENG":"While she does that, we have to rush in and take over their base ASAP!","TWN":"而我們則是要趁這個時候盡快佔領據點！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그나저나 용케 이 지하수도를 생각해냈다?","JPN":"それより、よくこの地下水道のことを思いついたよな。","ENG":"Gotta say, I'm impressed you thought of using the underground waterway.","TWN":"不過你怎麼會想到利用下水道？"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치가 속공 작전을 제안했을 때 떠올랐어요.","JPN":"コーチが速攻作戦を提案した時に思い浮かんだの。","ENG":"When Coach mentioned a fast break, it just came to me.","TWN":"教練建議使用快攻時想到的。"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"상업지구의 지하수도는 빈민가 사람들에겐 지긋지긋할 정도로 익숙하니까.","JPN":"商業地区の地下水道は、スラム街の住民ならイヤってほど慣れてるから。","ENG":"Since people from the slums are all too familiar with the commercial district's sewers.","TWN":"商業區的下水道對一般人而言是避之唯恐不及的，但對貧民來說卻非常熟悉。"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하! 그러고보니, 너랑 나랑 처음 만난 곳도 하수구였지?","JPN":"は！　そういえば、あんたと初めて出会ったのも下水道だったよな？","ENG":"Ha! Come to think of it, we first met in a place like this, right?","TWN":"哈！這麼說來，我和你第一次見面的地方也是下水道呢？"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하핫! 그땐 버려진 길고양이 같은 꼴이었는데 말이야!","JPN":"ははっ！　あの時は捨てられた野良猫みたいだったのにさ！","ENG":"Haha! You looked like a stray cat back then!","TWN":"哈哈，那時候的你看起來就像一隻流浪貓。"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대체 언제적 이야기에요? 그런 얘기 꺼낼 시간에 한 발이라도 더 쏴요!","JPN":"いったいいつの話？　そんなこと言っている暇があれば、一発でも多く撃って！","ENG":"That was a long time ago! Stop the chit-chat and shoot another round at them instead!","TWN":"都多久以前的事啦？有時間在這邊廢話，不如多射一發子彈吧！"},"stage":{"bg":"UNDER","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아, 이쪽은 얼추 정리됐나?","JPN":"よし、こっちはひとまず片付いたか？","ENG":"All right. Looks like this place has been mostly cleaned out.","TWN":"很好，這邊處理得差不多了吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"위로 나가면, 곧장 상대 거점에 도달할 수 있을 거예요.","JPN":"上に出れば、すぐ相手の拠点に到達できるはずよ。","ENG":"Once we go up, we'll be able to reach the opponent's base right away.","TWN":"現在只要往上走，就能直通對方的據點。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"상대도 바보는 아니니까 거점에 방어 병력을 남겨뒀겠죠.","JPN":"相手もバカじゃないから、拠点には防御戦力を残しておくはず。","ENG":"But they're not stupid, so they should have some guards placed there.","TWN":"但對方也不是笨蛋，一定會派人把守據點。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"마음의 준비를 해두는 게 좋을 거예요. 나가자마자 바로 총알이 쏟아질 테니까.","JPN":"心の準備をしておいた方がいいわ。出たとたんに弾丸が降り注ぐはずだから。","ENG":"Better get ready. As soon as we get out of here, it's going to be raining bullets.","TWN":"勸大家先做好心理準備，應該一出去子彈就會立刻射過來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇다고 여기서 꼬리를 내릴 수는 없잖냐?","JPN":"だからってここで尻尾をまいて逃げるわけにはいかないだろ？","ENG":"But we can't tuck in our tails and flee when we've come this far, right?","TWN":"現在已經無法回頭了吧？"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"가자! 이왕 이렇게 된 거 최단 기록을 갈아치워버리자고!","JPN":"行こう！　こうなったら、最短記録を更新してやろうじゃないか！","ENG":"Let's go! Let's set a new record for the fastest match while we're at it!","TWN":"走吧！我們趁這個機會刷新最短紀錄吧！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"좋아요! 다들 조금만 더 힘내요!","JPN":"そうですね！　みなさん、もうちょっと頑張りましょう！","ENG":"Okay! Let's all hang in there a little longer!","TWN":"好！大家再加把勁！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 노엘! 선배님들의 이름에 부끄럽지 않게 마지막까지 최선을 다하겠습니다!","JPN":"このノエル！　先輩たちの名を汚さないように、最後まで全力を尽くします！","ENG":"Noelle will do her best to make her seniors proud!","TWN":"我洛艾兒！一定會努力到最後一刻，不會讓前輩們丟臉的！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};